import { z } from 'zod';
import type { Experiment } from '../core/Experiment.js';
import type { Timeline } from '../core/Timeline.js';

export interface ValidationResult {
  valid: boolean;
  errors: ValidationError[];
  warnings: ValidationWarning[];
}

export interface ValidationError {
  type: 'error';
  code: string;
  message: string;
  path?: string;
  severity: 'critical' | 'high' | 'medium';
}

export interface ValidationWarning {
  type: 'warning';
  code: string;
  message: string;
  path?: string;
  recommendation?: string;
}

export interface ValidationOptions {
  strict?: boolean;
  checkTiming?: boolean;
  checkAccessibility?: boolean;
  checkPerformance?: boolean;
  maxDuration?: number;
  maxFileSize?: number;
}

export class Validator {
  private static readonly DEFAULT_OPTIONS: Required<ValidationOptions> = {
    strict: false,
    checkTiming: true,
    checkAccessibility: true,
    checkPerformance: true,
    maxDuration: 3600000, // 1 hour
    maxFileSize: 100 * 1024 * 1024, // 100MB
  };

  static validateExperiment(experiment: Experiment, options: ValidationOptions = {}): ValidationResult {
    const opts = { ...Validator.DEFAULT_OPTIONS, ...options };
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];

    // Basic validation from experiment's validate method
    const basicValidation = experiment.validate();
    if (!basicValidation.valid) {
      errors.push(...basicValidation.errors.map(error => ({
        type: 'error' as const,
        code: 'BASIC_VALIDATION',
        message: error,
        severity: 'critical' as const,
      })));
    }

    // Metadata validation
    Validator.validateMetadata(experiment, errors, warnings, opts);

    // Timeline validation
    Validator.validateTimelines(experiment, errors, warnings, opts);

    // Timing validation
    if (opts.checkTiming) {
      Validator.validateTiming(experiment, errors, warnings, opts);
    }

    // Accessibility validation
    if (opts.checkAccessibility) {
      Validator.validateAccessibility(experiment, errors, warnings, opts);
    }

    // Performance validation
    if (opts.checkPerformance) {
      Validator.validatePerformance(experiment, errors, warnings, opts);
    }

    return {
      valid: errors.length === 0,
      errors,
      warnings,
    };
  }

  private static validateMetadata(
    experiment: Experiment,
    errors: ValidationError[],
    warnings: ValidationWarning[],
    options: Required<ValidationOptions>
  ): void {
    const metadata = experiment.getMetadata();

    // Required fields
    if (!metadata.title || metadata.title.trim().length === 0) {
      errors.push({
        type: 'error',
        code: 'MISSING_TITLE',
        message: 'Experiment title is required',
        path: 'metadata.title',
        severity: 'critical',
      });
    }

    if (!metadata.version || metadata.version.trim().length === 0) {
      errors.push({
        type: 'error',
        code: 'MISSING_VERSION',
        message: 'Experiment version is required',
        path: 'metadata.version',
        severity: 'critical',
      });
    }

    // Version format validation
    if (metadata.version && !/^\d+\.\d+\.\d+/.test(metadata.version)) {
      warnings.push({
        type: 'warning',
        code: 'INVALID_VERSION_FORMAT',
        message: 'Version should follow semantic versioning (e.g., 1.0.0)',
        path: 'metadata.version',
        recommendation: 'Use semantic versioning format: MAJOR.MINOR.PATCH',
      });
    }

    // Recommended fields
    if (!metadata.description) {
      warnings.push({
        type: 'warning',
        code: 'MISSING_DESCRIPTION',
        message: 'Experiment description is recommended for better documentation',
        path: 'metadata.description',
        recommendation: 'Add a description explaining the experiment purpose and procedure',
      });
    }

    if (!metadata.author) {
      warnings.push({
        type: 'warning',
        code: 'MISSING_AUTHOR',
        message: 'Author information is recommended for proper attribution',
        path: 'metadata.author',
        recommendation: 'Add author name and contact information',
      });
    }

    // DOI validation
    if (metadata.doi && !/^10\.\d{4,}\//.test(metadata.doi)) {
      errors.push({
        type: 'error',
        code: 'INVALID_DOI',
        message: 'DOI format is invalid',
        path: 'metadata.doi',
        severity: 'medium',
      });
    }

    // Tags validation
    if (metadata.tags && metadata.tags.length === 0) {
      warnings.push({
        type: 'warning',
        code: 'NO_TAGS',
        message: 'Tags help with experiment discoverability',
        path: 'metadata.tags',
        recommendation: 'Add relevant tags describing the experiment type and domain',
      });
    }
  }

  private static validateTimelines(
    experiment: Experiment,
    errors: ValidationError[],
    warnings: ValidationWarning[],
    options: Required<ValidationOptions>
  ): void {
    const timelines = experiment.getTimelines();

    if (timelines.length === 0) {
      errors.push({
        type: 'error',
        code: 'NO_TIMELINES',
        message: 'Experiment must have at least one timeline',
        severity: 'critical',
      });
      return;
    }

    // Validate each timeline
    timelines.forEach((timeline, index) => {
      const path = `timelines[${index}]`;

      // Check for empty timelines
      if (timeline.getItems().length === 0) {
        errors.push({
          type: 'error',
          code: 'EMPTY_TIMELINE',
          message: `Timeline '${timeline.id}' is empty`,
          path,
          severity: 'high',
        });
      }

      // Check timeline options
      const options = timeline.getOptions();

      // Validate repeat count
      if (options.repeat !== undefined && options.repeat <= 0) {
        errors.push({
          type: 'error',
          code: 'INVALID_REPEAT_COUNT',
          message: `Timeline '${timeline.id}' has invalid repeat count: ${options.repeat}`,
          path: `${path}.repeat`,
          severity: 'medium',
        });
      }

      // Warn about very high repeat counts
      if (options.repeat !== undefined && options.repeat > 1000) {
        warnings.push({
          type: 'warning',
          code: 'HIGH_REPEAT_COUNT',
          message: `Timeline '${timeline.id}' has very high repeat count: ${options.repeat}`,
          path: `${path}.repeat`,
          recommendation: 'Consider breaking into smaller chunks for better performance',
        });
      }

      // Validate conditions
      if (options.conditions && options.conditions.length === 0) {
        warnings.push({
          type: 'warning',
          code: 'EMPTY_CONDITIONS',
          message: `Timeline '${timeline.id}' has empty conditions array`,
          path: `${path}.conditions`,
          recommendation: 'Remove empty conditions array or add conditions',
        });
      }
    });
  }

  private static validateTiming(
    experiment: Experiment,
    errors: ValidationError[],
    warnings: ValidationWarning[],
    options: Required<ValidationOptions>
  ): void {
    // Estimate total experiment duration
    let estimatedDuration = 0;
    let hasUnlimitedDuration = false;

    experiment.getTimelines().forEach((timeline, timelineIndex) => {
      const timelineOptions = timeline.getOptions();
      const repeatCount = timelineOptions.repeat || 1;
      const conditionCount = timelineOptions.conditions?.length || 1;

      timeline.getItems().forEach((item, itemIndex) => {
        const path = `timelines[${timelineIndex}].items[${itemIndex}]`;

        if (item.duration) {
          estimatedDuration += item.duration * repeatCount * conditionCount;
        } else {
          hasUnlimitedDuration = true;
          warnings.push({
            type: 'warning',
            code: 'UNLIMITED_DURATION',
            message: `Item '${item.id}' has no specified duration`,
            path,
            recommendation: 'Consider adding timeout or duration for better user experience',
          });
        }

        // Check for very short durations (potential timing issues)
        if (item.duration && item.duration < 16) {
          warnings.push({
            type: 'warning',
            code: 'SHORT_DURATION',
            message: `Item '${item.id}' has very short duration: ${item.duration}ms`,
            path,
            recommendation: 'Durations under 16ms may not be reliable due to display refresh rates',
          });
        }

        // Check for very long durations
        if (item.duration && item.duration > 60000) {
          warnings.push({
            type: 'warning',
            code: 'LONG_DURATION',
            message: `Item '${item.id}' has long duration: ${item.duration}ms`,
            path,
            recommendation: 'Consider breaking long stimuli into smaller segments',
          });
        }
      });
    });

    // Check total duration
    if (!hasUnlimitedDuration && estimatedDuration > options.maxDuration) {
      errors.push({
        type: 'error',
        code: 'EXPERIMENT_TOO_LONG',
        message: `Estimated experiment duration (${Math.round(estimatedDuration / 1000)}s) exceeds maximum (${Math.round(options.maxDuration / 1000)}s)`,
        severity: 'medium',
      });
    }

    if (estimatedDuration > 1800000) { // 30 minutes
      warnings.push({
        type: 'warning',
        code: 'LONG_EXPERIMENT',
        message: `Experiment duration is quite long (${Math.round(estimatedDuration / 60000)} minutes)`,
        recommendation: 'Consider adding breaks or splitting into multiple sessions',
      });
    }
  }

  private static validateAccessibility(
    experiment: Experiment,
    errors: ValidationError[],
    warnings: ValidationWarning[],
    options: Required<ValidationOptions>
  ): void {
    // This would check for accessibility issues
    // For now, basic checks based on stimuli types

    experiment.getTimelines().forEach((timeline, timelineIndex) => {
      timeline.getItems().forEach((item, itemIndex) => {
        const path = `timelines[${timelineIndex}].items[${itemIndex}]`;

        // Check for missing alt text on images
        if ('options' in item && item.constructor.name === 'ImageStimulus') {
          const imageItem = item as any;
          if (!imageItem.options?.alt) {
            warnings.push({
              type: 'warning',
              code: 'MISSING_ALT_TEXT',
              message: `Image stimulus '${item.id}' is missing alt text`,
              path,
              recommendation: 'Add alt text for screen reader accessibility',
            });
          }
        }

        // Check for audio-only content
        if (item.constructor.name === 'AudioStimulus') {
          warnings.push({
            type: 'warning',
            code: 'AUDIO_ONLY',
            message: `Audio stimulus '${item.id}' may not be accessible to hearing-impaired users`,
            path,
            recommendation: 'Consider providing captions or visual alternatives',
          });
        }
      });
    });
  }

  private static validatePerformance(
    experiment: Experiment,
    errors: ValidationError[],
    warnings: ValidationWarning[],
    options: Required<ValidationOptions>
  ): void {
    let totalAssetCount = 0;
    let videoCount = 0;
    let audioCount = 0;

    experiment.getTimelines().forEach((timeline, timelineIndex) => {
      timeline.getItems().forEach((item, itemIndex) => {
        const path = `timelines[${timelineIndex}].items[${itemIndex}]`;

        // Count media assets
        if (item.constructor.name.includes('Stimulus')) {
          totalAssetCount++;

          if (item.constructor.name === 'VideoStimulus') {
            videoCount++;
          } else if (item.constructor.name === 'AudioStimulus') {
            audioCount++;
          }
        }
      });
    });

    // Warn about many assets
    if (totalAssetCount > 50) {
      warnings.push({
        type: 'warning',
        code: 'MANY_ASSETS',
        message: `Experiment has many assets (${totalAssetCount})`,
        recommendation: 'Consider preloading assets or optimizing asset sizes',
      });
    }

    // Warn about many video files
    if (videoCount > 10) {
      warnings.push({
        type: 'warning',
        code: 'MANY_VIDEOS',
        message: `Experiment has many video stimuli (${videoCount})`,
        recommendation: 'Video files can be large; ensure good network connectivity',
      });
    }

    // Warn about concurrent media
    if (audioCount > 0 && videoCount > 0) {
      warnings.push({
        type: 'warning',
        code: 'MIXED_MEDIA',
        message: 'Experiment mixes audio and video stimuli',
        recommendation: 'Test on target devices to ensure smooth playback',
      });
    }
  }

  // Quick validation for common use cases
  static quickValidate(experiment: Experiment): boolean {
    const result = Validator.validateExperiment(experiment, { strict: false });
    return result.valid;
  }

  static strictValidate(experiment: Experiment): ValidationResult {
    return Validator.validateExperiment(experiment, { strict: true });
  }

  // Validation schemas for serialized data
  static getExperimentSchema() {
    return z.object({
      type: z.literal('Experiment'),
      metadata: z.object({
        title: z.string().min(1),
        description: z.string().optional(),
        version: z.string().min(1),
        author: z.string().optional(),
        institution: z.string().optional(),
        doi: z.string().optional(),
        license: z.string().optional(),
        tags: z.array(z.string()).optional(),
        created: z.number(),
        modified: z.number(),
        psychoforgeVersion: z.string(),
      }),
      options: z.record(z.unknown()).optional(),
      timelines: z.array(z.record(z.unknown())),
    });
  }
}

