/**
 * Task priority levels for hierarchical scheduling
 * Higher numbers indicate higher priority (executed first)
 */
export enum TaskPriority {
  /** Lowest priority - background tasks, cleanup operations */
  BACKGROUND = 0,

  /** Normal priority - standard experiment logic */
  NORMAL = 1,

  /** High priority - stimulus presentation, response collection */
  HIGH = 2,

  /** Critical priority - timing-sensitive operations */
  CRITICAL = 3,

  /** Real-time priority - frame-synchronous operations */
  REALTIME = 4
}

/**
 * Utility functions for working with task priorities
 */
export class TaskPriorityUtils {
  /**
   * Compare two priorities for sorting (higher priority first)
   */
  static compare(a: TaskPriority, b: TaskPriority): number {
    return b - a; // Descending order (higher numbers first)
  }

  /**
   * Check if a priority level is time-critical
   */
  static isCritical(priority: TaskPriority): boolean {
    return priority >= TaskPriority.CRITICAL;
  }

  /**
   * Get human-readable priority name
   */
  static getName(priority: TaskPriority): string {
    switch (priority) {
      case TaskPriority.BACKGROUND: return 'BACKGROUND';
      case TaskPriority.NORMAL: return 'NORMAL';
      case TaskPriority.HIGH: return 'HIGH';
      case TaskPriority.CRITICAL: return 'CRITICAL';
      case TaskPriority.REALTIME: return 'REALTIME';
      default: return 'UNKNOWN';
    }
  }
}

/**
 * Classic Stroop Color-Word Interference Task
 * 
 * This example demonstrates:
 * - Timeline creation and nesting
 * - Dynamic stimulus content
 * - Response collection and validation
 * - Conditional logic and randomization
 * - Data collection and analysis
 */

import { ForgeScript } from '../src/index.js';

// Create the experiment
const stroopExperiment = ForgeScript.createExperiment('Stroop Color-Word Task')
  .title('Stroop Color-Word Interference Task')
  .description('A classic cognitive psychology experiment measuring selective attention and processing speed')
  .version('1.0.0')
  .author('Psychology Research Lab')
  .tags(['attention', 'stroop', 'cognitive psychology', 'interference']);

// Define stimulus sets
const colorWords = ['RED', 'GREEN', 'BLUE', 'YELLOW'];
const colors = ['red', 'green', 'blue', 'yellow'];
const keyMapping = { 'red': 'r', 'green': 'g', 'blue': 'b', 'yellow': 'y' };

// Welcome and consent
const welcomeTimeline = ForgeScript.createTimeline('welcome')
  .add(ForgeScript.createTextStimulus('Welcome to the Stroop Task!', 3000)
    .fontSize(36)
    .color('black'))
  .add(ForgeScript.createTextStimulus(
    'In this experiment, you will see words displayed in different colors.\n\n' +
    'Your task is to identify the COLOR of the text, not the word itself.\n\n' +
    'Press SPACE to continue...'
  )
    .fontSize(20)
    .color('black'))
  .add(ForgeScript.createKeyboardResponse(['space']));

// Instructions with examples
const instructionsTimeline = ForgeScript.createTimeline('instructions')
  .add(ForgeScript.createTextStimulus(
    'Response Keys:\n\n' +
    'R = Red    G = Green    B = Blue    Y = Yellow\n\n' +
    'Remember: Respond to the COLOR, not the word!', 5000
  )
    .fontSize(18)
    .color('black'))
  .add(ForgeScript.createTextStimulus('Let\'s try a few practice trials...', 2000)
    .fontSize(20)
    .color('black'));

// Practice trials
const practiceConditions = [
  { word: 'RED', color: 'red', congruent: true },
  { word: 'BLUE', color: 'green', congruent: false },
  { word: 'GREEN', color: 'blue', congruent: false },
];

