**HIGH** File:`packages/scheduling/src/Scheduler.ts:379` – Scheduler uses an O(n) linear search for task insertion, posing a performance risk
→ **Issue**: The `_insertTaskByPriority` method uses `findIndex` to locate the insertion point in the `_taskQueue`. This is a linear search with O(n) time complexity. For a scheduler designed for high-precision, real-time experiments, this will become a significant bottleneck as the number of scheduled tasks increases, potentially causing dropped frames and inaccurate timing.

→ **Fix**: Replace the array-based queue with a more efficient data structure like a **Min-Heap (Priority Queue)**. This will reduce insertion complexity to O(log n). Libraries like `tinyqueue` or a custom heap implementation can be used.

```typescript
// packages/scheduling/src/Scheduler.ts

// Simplified example of a heap-based approach
import TinyQueue from 'tinyqueue';

// ... inside Scheduler class

// Replace: private _taskQueue: ScheduledTask[] = [];
private _taskQueue: TinyQueue<ScheduledTask>;

constructor(options: SchedulerOptions = {}) {
  // ...
  // Initialize the priority queue
  this._taskQueue = new TinyQueue([], (a, b) => {
    const priorityDiff = TaskPriorityUtils.compare(a.task.priority, b.task.priority);
    if (priorityDiff !== 0) return priorityDiff;
    return a.scheduledTime - b.scheduledTime;
  });
}

private _insertTaskByPriority(scheduledTask: ScheduledTask): void {
  this._taskQueue.push(scheduledTask);
}

private _getReadyTasks(currentTime: number): ScheduledTask[] {
  const readyTasks: ScheduledTask[] = [];
  const tolerance = this._options.timingTolerance;

  while (this._taskQueue.length > 0 && this._taskQueue.peek().scheduledTime <= currentTime + tolerance) {
    readyTasks.push(this._taskQueue.pop());
  }

  // Note: The original sort logic is now handled by the priority queue's comparator.
  return readyTasks;
}
```

