**MEDIUM** File:`packages/devices/src/DeviceManager.ts:215` – Repetitive and hard-to-maintain event forwarding logic
→ **Issue**: The `addDevice` method contains a long chain of `if (device instanceof ...)` blocks to attach event listeners. This pattern is not scalable; adding a new device type or a new event requires modifying this method, violating the Open/Closed Principle.

→ **Fix**: Refactor this logic to be data-driven. Define the events for each device type in a configuration object and loop through it to attach listeners.

```typescript
// packages/devices/src/DeviceManager.ts

// Define event maps for each device type
const deviceEventMap = {
  KeyboardDevice: ['keydown', 'keyup', 'keypress'],
  MouseDevice: ['click', 'mousedown', 'mouseup', 'mousemove', 'wheel', 'contextmenu'],
  TouchDevice: ['touchstart', 'touchmove', 'touchend', 'touchcancel', 'deviceorientation'],
  AudioDevice: ['recordingstarted', 'recordingstopped', 'soundplayed', 'toneplayed', 'audiolevel', 'devicechange'],
  VideoDevice: ['capturestarted', 'capturestopped', 'videoelement', 'phototaken', 'devicechange'],
};

// ... inside DeviceManager class
private addDevice(device: Device): void {
  this.devices.set(device.id, device);

  const forwardEvent = (event: DeviceEvent) => {
    this.emitEvent(event.type, event.data);
    this.emitEvent('deviceevent', event);
  };

  // Forward common events
  ['connected', 'disconnected', 'error'].forEach(eventType => {
    device.addEventListener(eventType, forwardEvent);
  });

  // Forward device-specific events
  const deviceType = device.constructor.name;
  const specificEvents = deviceEventMap[deviceType];
  if (specificEvents) {
    specificEvents.forEach(eventType => {
      device.addEventListener(eventType, forwardEvent);
    });
  }

  this.emitEvent('deviceadded', { 
    deviceId: device.id, 
    deviceType: device.deviceType,
    isConnected: device.isConnected 
  });
}
```

